// ── Hooks ────────────────────────────────────────────────────────────────────
function useTyping(words, sp=90, dsp=45, pause=1900) {
  const [st, setSt] = useState({txt:'',wi:0,del:false,pausing:false});
  useEffect(() => {
    if (st.pausing) {
      const t = setTimeout(() => setSt(s=>({...s,pausing:false,del:true})), pause);
      return () => clearTimeout(t);
    }
    const word = words[st.wi];
    const t = setTimeout(() => {
      if (!st.del) {
        const next = word.slice(0, st.txt.length+1);
        if (next===word) setSt(s=>({...s,txt:next,pausing:true}));
        else setSt(s=>({...s,txt:next}));
      } else {
        const next = st.txt.slice(0,-1);
        if (next==='') setSt(s=>({...s,txt:'',del:false,wi:(s.wi+1)%words.length}));
        else setSt(s=>({...s,txt:next}));
      }
    }, st.del ? dsp : sp);
    return () => clearTimeout(t);
  }, [st, words, sp, dsp, pause]);
  return st.txt;
}

// ── Particles ────────────────────────────────────────────────────────────────
function Particles() {
  const ref = useRef(null);
  useEffect(() => {
    const cv = ref.current; if (!cv) return;
    const ctx = cv.getContext('2d');
    let aid;
    const resize = () => { cv.width=cv.offsetWidth; cv.height=cv.offsetHeight; };
    resize();
    const ro = new ResizeObserver(resize); ro.observe(cv);
    const pts = Array.from({length:65},()=>({
      x:Math.random()*cv.width, y:Math.random()*cv.height,
      vx:(Math.random()-.5)*.25, vy:(Math.random()-.5)*.25,
      sz:Math.random()*1.4+.5, a:Math.random()*.5+.2
    }));
    function draw() {
      ctx.clearRect(0,0,cv.width,cv.height);
      for (let i=0;i<pts.length;i++) {
        for (let j=i+1;j<pts.length;j++) {
          const d=Math.hypot(pts[i].x-pts[j].x,pts[i].y-pts[j].y);
          if (d<110) {
            ctx.globalAlpha=(1-d/110)*.1;
            ctx.strokeStyle='#00d4ff'; ctx.lineWidth=.5;
            ctx.beginPath(); ctx.moveTo(pts[i].x,pts[i].y); ctx.lineTo(pts[j].x,pts[j].y); ctx.stroke();
          }
        }
      }
      pts.forEach(p=>{
        ctx.globalAlpha=p.a;
        ctx.fillStyle='#00d4ff'; ctx.shadowBlur=8; ctx.shadowColor='#00d4ff';
        ctx.beginPath(); ctx.arc(p.x,p.y,p.sz,0,Math.PI*2); ctx.fill();
        ctx.shadowBlur=0;
        p.x+=p.vx; p.y+=p.vy;
        if(p.x<0||p.x>cv.width) p.vx*=-1;
        if(p.y<0||p.y>cv.height) p.vy*=-1;
      });
      ctx.globalAlpha=1;
      aid=requestAnimationFrame(draw);
    }
    draw();
    return () => { cancelAnimationFrame(aid); ro.disconnect(); };
  }, []);
  return <canvas ref={ref} style={{position:'absolute',inset:0,width:'100%',height:'100%',pointerEvents:'none'}} />;
}

