// ── Journey ────────────────────────────────────────────────────────────────
function Journey() {
  const statusStyle=(s)=>({
    done:{bg:'rgba(0,212,255,.1)',c:'#00d4ff',b:'rgba(0,212,255,.3)',l:'DONE'},
    active:{bg:'rgba(0,255,100,.08)',c:'#00ff64',b:'rgba(0,255,100,.3)',l:'ACTIVE'},
    upcoming:{bg:'rgba(255,255,255,.04)',c:'#475569',b:'rgba(255,255,255,.08)',l:'UPCOMING'},
  }[s]);
  return (
    <section id="journey" style={{padding:'100px 6%',background:'#050508'}}>
      <div style={{maxWidth:760,margin:'0 auto'}}>
        <SHead pre="// TIMELINE" title="Learning" hl="Journey"/>
        <div style={{position:'relative',paddingLeft:42}}>
          <div className="tline"/>
          {JOURNEY.map((j,i)=>{
            const ss=statusStyle(j.s);
            return (
              <div key={i} className={`reveal d${Math.min(i+1,4)}`} style={{display:'flex',gap:22,paddingBottom:32,position:'relative'}}>
                <div className="tdot" style={{marginTop:3,background:j.s==='upcoming'?'rgba(0,212,255,.15)':'linear-gradient(135deg,#0066ff,#00d4ff)',border:j.s==='upcoming'?'1px dashed rgba(0,212,255,.35)':'none'}}/>
                <div className="glass sc" style={{flex:1,padding:'20px 24px'}}>
                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:8,flexWrap:'wrap',gap:8}}>
                    <div style={{display:'flex',alignItems:'center',gap:12}}>
                      <span style={{fontSize:'1.15rem'}}>{j.icon}</span>
                      <h4 className="fo" style={{color:'#e2e8f0',fontSize:'.84rem',fontWeight:600}}>{j.title}</h4>
                    </div>
                    <div style={{display:'flex',gap:8,alignItems:'center'}}>
                      <span className="fm" style={{color:'#2d3d55',fontSize:'.72rem'}}>{j.year}</span>
                      <span style={{padding:'2px 10px',borderRadius:20,fontSize:'.68rem',fontFamily:'JetBrains Mono',background:ss.bg,color:ss.c,border:`1px solid ${ss.b}`}}>{ss.l}</span>
                    </div>
                  </div>
                  <p style={{color:'#4e6080',fontSize:'.85rem'}}>{j.desc}</p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

