// ── App ────────────────────────────────────────────────────────────────────
export default function App() {
  const [loading,setLoading]=useState(true);
  const [scrollPct,setScrollPct]=useState(0);
  const [cursor,setCursor]=useState({x:-500,y:-500});
  const [menu,setMenu]=useState(false);


  // Scroll reveal
  useEffect(()=>{
    if(loading)return;
    const obs=new IntersectionObserver(entries=>entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('vis');}),{threshold:.1});
    const t=setTimeout(()=>{document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));},150);
    return()=>{clearTimeout(t);obs.disconnect();};
  },[loading]);

  // Scroll progress
  useEffect(()=>{
    const h=()=>{const tot=document.documentElement.scrollHeight-window.innerHeight;setScrollPct((window.scrollY/tot)*100);};
    window.addEventListener('scroll',h);
    return()=>window.removeEventListener('scroll',h);
  },[]);

  // Cursor glow
  useEffect(()=>{
    const h=(e)=>setCursor({x:e.clientX,y:e.clientY});
    window.addEventListener('mousemove',h);
    return()=>window.removeEventListener('mousemove',h);
  },[]);

  const scrollTo=(id)=>{
    document.getElementById(id)?.scrollIntoView({behavior:'smooth'});
    setMenu(false);
  };

  if(loading) return <><style>{CSS}</style><Loader onDone={()=>setLoading(false)}/></>;

  return (
    <>
      <style>{CSS}</style>
      {/* Cursor glow */}
      <div style={{position:'fixed',width:380,height:380,borderRadius:'50%',background:'radial-gradient(circle,rgba(0,212,255,.04) 0%,transparent 70%)',pointerEvents:'none',left:cursor.x,top:cursor.y,transform:'translate(-50%,-50%)',zIndex:9999,transition:'left .18s,top .18s'}}/>
      {/* Scroll progress bar */}
      <div style={{position:'fixed',top:0,left:0,height:2,width:`${scrollPct}%`,background:'linear-gradient(90deg,#0066ff,#00d4ff)',boxShadow:'0 0 10px #00d4ff',zIndex:1000,transition:'width .1s'}}/>

      <Navbar scrollTo={scrollTo} menu={menu} setMenu={setMenu}/>
      <main>
        <Hero scrollTo={scrollTo}/>
        <About/>
        <Skills/>
        <Projects/>
        <Journey/>
        <Services/>
        <GH/>
        <Certs/>
        <Contact/>
      </main>
      <Footer scrollTo={scrollTo}/>
    </>
  );
}
